<?php
namespace App\Services\Production;
use App\Models\{Branch,Item,ProductionBom,ProductionBomMaterial,ProductionBomOutput,User,Warehouse}; use App\Services\DocumentSequenceService; use Illuminate\Support\Facades\DB; use Illuminate\Validation\ValidationException; use RuntimeException;
class ProductionBomService { public function __construct(private DocumentSequenceService $numbers){}
 public function create(array $data,User $actor):ProductionBom{return DB::transaction(function()use($data,$actor){$this->validate($data,$actor);$item=Item::findOrFail($data['finished_item_id']);$version=$data['version']??$this->nextVersion((int)$data['company_id'],$item->id);$bom=ProductionBom::create($this->header($data,$actor)+['number'=>$this->numbers->generate('PRODUCTION_BOM',$data['company_id'],$data['branch_id']??null),'version'=>$version,'status'=>ProductionBom::STATUS_DRAFT,'created_by'=>$actor->id]);$this->syncLines($bom,$data);return $bom->load(['materials.item.baseUnit','outputs']);});}
 public function update(ProductionBom $bom,array $data,User $actor):ProductionBom{return DB::transaction(function()use($bom,$data,$actor){$bom=ProductionBom::lockForUpdate()->findOrFail($bom->id);if($bom->status!==ProductionBom::STATUS_DRAFT)throw new RuntimeException('Only draft formulas can be edited.');$this->validate($data,$actor,$bom);$bom->update($this->header($data,$actor)+['version'=>$data['version']??$bom->version]);$this->syncLines($bom,$data);return $bom->fresh(['materials.item.baseUnit','outputs']);});}
 public function activate(ProductionBom $bom,User $actor):void{DB::transaction(function()use($bom,$actor){$bom=ProductionBom::with(['materials.item','outputs'])->lockForUpdate()->findOrFail($bom->id);if(!in_array($bom->status,[ProductionBom::STATUS_DRAFT,ProductionBom::STATUS_INACTIVE],true))throw new RuntimeException('Formula cannot be activated from its current status.');$this->validateModel($bom);$conflict=ProductionBom::active()->where('company_id',$bom->company_id)->where('finished_item_id',$bom->finished_item_id)->whereKeyNot($bom->id)->where(fn($q)=>$bom->branch_id?$q->where('branch_id',$bom->branch_id):$q->whereNull('branch_id'))->where(fn($q)=>$q->whereNull('effective_to')->orWhere('effective_to','>=',$bom->effective_from??'0001-01-01'))->where(fn($q)=>$q->whereNull('effective_from')->orWhere('effective_from','<=',$bom->effective_to??'9999-12-31'))->exists();if($conflict)throw ValidationException::withMessages(['effective_from'=>'An active formula already overlaps this applicability and period.']);$bom->update(['status'=>ProductionBom::STATUS_ACTIVE,'activated_by'=>$actor->id,'activated_at'=>now()]);});}
 public function inactivate(ProductionBom $bom,User $actor):void{$this->transition($bom,ProductionBom::STATUS_ACTIVE,ProductionBom::STATUS_INACTIVE,['inactivated_by'=>$actor->id,'inactivated_at'=>now()]);} public function obsolete(ProductionBom $bom,User $actor):void{$this->transition($bom,ProductionBom::STATUS_INACTIVE,ProductionBom::STATUS_OBSOLETE,['updated_by'=>$actor->id]);}
 public function clone(ProductionBom $source,User $actor):ProductionBom{return DB::transaction(function()use($source,$actor){$source=ProductionBom::with(['materials','outputs'])->lockForUpdate()->findOrFail($source->id);$data=$source->only(['company_id','branch_id','name','production_type','finished_item_id','base_output_quantity','output_uom_id','default_source_warehouse_id','default_destination_warehouse_id','effective_from','effective_to','notes']);$data['name']='Copy of '.$source->name;$data['version']=$this->nextVersion($source->company_id,$source->finished_item_id);$data['materials']=$source->materials->map->only(['item_id','quantity','uom_id','quantity_type','source_warehouse_id','notes'])->all();return $this->create($data,$actor);});}
 public function nextVersion(int $company,int $item):int{Item::whereKey($item)->lockForUpdate()->firstOrFail();ProductionBom::where('company_id',$company)->where('finished_item_id',$item)->lockForUpdate()->get();return (int)ProductionBom::where('company_id',$company)->where('finished_item_id',$item)->max('version')+1;}
 private function header(array $d,User $a):array{if(!$a->isSuperAdmin()&&!$a->branches()->where('company_id',$d['company_id'])->exists())$this->fail('company_id','You cannot access this company.');$eligibility=app(ProductionItemEligibility::class);$finished=Item::findOrFail($d['finished_item_id']);if(!$eligibility->isOutput($finished))$this->fail('finished_item_id','Finished item must be an eligible Finished Goods or Semi-Finished inventory item.');foreach($d['materials']as$i=>$line){$material=Item::findOrFail($line['item_id']);if(!$eligibility->isMaterial($material,$d['production_type']))$this->fail("materials.$i.item_id",$d['production_type']===ProductionBom::TYPE_REPACKING?'Material is not eligible for repacking.':'STANDARD materials must be Raw Material, Packaging, Consumable, or Semi-Finished inventory items.');}return collect($d)->only(['company_id','branch_id','name','production_type','finished_item_id','base_output_quantity','output_uom_id','default_source_warehouse_id','default_destination_warehouse_id','effective_from','effective_to','notes'])->all()+['updated_by'=>$a->id];}
 private function syncLines(ProductionBom $b,array $d):void{$b->materials()->delete();foreach(array_values($d['materials'])as$i=>$line)$b->materials()->create($line+['sequence'=>$i+1]);$b->outputs()->delete();$b->outputs()->create(['item_id'=>$d['finished_item_id'],'output_type'=>ProductionBomOutput::TYPE_MAIN,'quantity'=>$d['base_output_quantity'],'uom_id'=>$d['output_uom_id'],'destination_warehouse_id'=>$d['default_destination_warehouse_id']??null,'sequence'=>1]);}
 private function validate(array $d,User $u,?ProductionBom $current=null):void{$branch=filled($d['branch_id']??null)?Branch::find($d['branch_id']):null;if($branch&&(int)$branch->company_id!==(int)$d['company_id'])$this->fail('branch_id','Branch must belong to the selected company.');if(!$u->isSuperAdmin()&&$branch&&!$u->branches()->whereKey($branch->id)->exists())$this->fail('branch_id','You cannot access this branch.');$finished=Item::findOrFail($d['finished_item_id']);if(!$finished->is_active||!$finished->track_inventory||!$finished->base_unit_id)$this->fail('finished_item_id','Finished item must be active, inventory tracked, and have a base UOM.');if((int)$d['output_uom_id']!==(int)$finished->base_unit_id)$this->fail('output_uom_id','Output UOM must equal the finished item base UOM.');$seen=[];foreach($d['materials']as$i=>$line){$item=Item::findOrFail($line['item_id']);if((int)$item->id===(int)$finished->id)$this->fail("materials.$i.item_id",'Material cannot equal the main output item.');if(isset($seen[$item->id]))$this->fail("materials.$i.item_id",'Duplicate material items are not supported.');$seen[$item->id]=true;if(!$item->is_active||!$item->track_inventory||(int)$line['uom_id']!==(int)$item->base_unit_id)$this->fail("materials.$i.uom_id",'Material must be active, tracked, and use its base UOM.');$this->warehouse($line['source_warehouse_id']??$d['default_source_warehouse_id']??null,$d,$i?'materials.'.$i.'.source_warehouse_id':'default_source_warehouse_id',$u);}$this->warehouse($d['default_destination_warehouse_id']??null,$d,'default_destination_warehouse_id',$u,true);}
 private function warehouse($id,array$d,string$key,User$u,bool$destination=false):void{if(!$id)return;$w=Warehouse::with('warehouseType')->findOrFail($id);if(!$w->is_active||(int)($w->company_id?:$w->branch?->company_id)!==(int)$d['company_id']||(!empty($d['branch_id'])&&(int)$w->branch_id!==(int)$d['branch_id'])||(!$u->isSuperAdmin()&&!$u->branches()->whereKey($w->branch_id)->exists()))$this->fail($key,'Warehouse is inactive or outside your accessible Formula company/branch.');if($destination&&!in_array($w->warehouseType?->code,['FINISHED_GOODS','PRODUCTION'],true))$this->fail($key,'Default destination must be a Finished Goods or Production warehouse.');}
 private function validateModel(ProductionBom$b):void{if($b->materials->isEmpty()||$b->outputs->where('output_type',ProductionBomOutput::TYPE_MAIN)->count()!==1)throw new RuntimeException('Formula requires materials and exactly one main output.');} private function transition(ProductionBom$b,string$from,string$to,array$extra):void{DB::transaction(function()use($b,$from,$to,$extra){$b=ProductionBom::lockForUpdate()->findOrFail($b->id);if($b->status!==$from)throw new RuntimeException('Invalid Formula status transition.');$b->update(['status'=>$to]+$extra);});} private function fail(string$key,string$msg):never{throw ValidationException::withMessages([$key=>$msg]);}
}
